INSERT INTO `sys_movie` VALUES (1,'八角笼中',120,'[\"/images/movie/2023/07/08/b62fd514a5b7408e9cd41b228b1195b9.jpg\"]','中国大陆','2026-07-28 00:00:00',326.00,'年度最受期待现实佳作！根据真实事件改编，王宝强诚意打造普通人改写命运之路！电影讲述了向腾辉（王宝强 饰）倾注心血想把当地无人照料的孩子培养成才，这让生活本没有出路的孩子们看到了一丝通向未来的曙光。然而，随着往日的表演视频被爆出，这些“残忍、血腥”的画面刺激了不明真相的人们的神经。一夜之间，舆论开始发酵。向腾辉的生活、孩子们的前途都陷入到人们以善良为名编织的大网中，让 他们难以挣脱，重回泥沼，关于未来，他们的“出路”又将在哪……','[\"/images/movie/2023/07/08/d719ce09e35347999b243847f1eab610.jpg\", \"/images/movie/2023/07/08/e56b01ef8b2748a4812760ff94ccffcc.jpg\", \"/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg\", \"/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg\", \"/images/movie/2023/07/08/f5c6d4b533a6433faaa74f972cfe6bce.jpg\"]',0),(2,'消失的她',120,'[\"/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg\"]','中国大陆','2026-08-01 00:00:00',348.00,'金牌监制陈思诚继《误杀》系列后又一悬疑力作，朱一龙、倪妮、文咏珊、杜江俊男美女狂飙演技，剧情过山车反转停不下来！何非（朱一龙 饰）的妻子李木子（文咏珊 饰）在结婚周年旅行中离奇消失，在何非苦寻无果之时妻子再次现身，何非却坚持眼前的陌生女人并非妻子，妻子拿出了身份证明进行自证，夫妻二人似乎都有不可告人的秘密，随着金牌律师陈麦（倪妮 饰）介入到这起离奇案件中，更多的谜团慢慢浮现……究竟谁在说谎？端午佳节一起沉浸解谜。','[\"/images/movie/2023/07/08/a546b6b4277844328dc1e4c52c9c6a69.jpg\", \"/images/movie/2023/07/08/b37d19c3ae304aefb6ef8bf99437e85d.jpg\", \"/images/movie/2023/07/08/a64c759d80e746b9a6c80b1181cd6ca0.jpg\", \"/images/movie/2023/07/08/c62af834ee5c49d29b9d7e17a0133d64.jpg\", \"/images/movie/2023/07/08/9c7b4cff4fa8438393df319c6d58a195.jpg\"]',0),(3,'长安三万里',120,'[\"/images/movie/2023/07/08/a284e9179d954164b15448ef25277df3.jpg\"]','中国大陆','2026-08-05 00:00:00',0.00,'安史之乱爆发后数年，吐蕃大军攻打西南。大唐节度使高适交战不利，长安岌岌可危。困守孤城的高适向监军太监回忆起自己与李白的一生往事。','[\"/images/movie/2023/07/08/51bec9afe30045f78d456dd27f50f6db.jpg\", \"/images/movie/2023/07/08/f2d5f2baf63f4316b025a04d29cd2cbb.jpg\", \"/images/movie/2023/07/08/b93b27fa19214cc9b4a4c45876e1c866.jpg\", \"/images/movie/2023/07/08/559b24d427a2427885424af59dce96c9.jpg\", \"/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg\"]',0),(4,'扫毒3：人在天涯',120,'[\"/images/movie/2023/07/08/bbaadec5d93e4c9ca5f7b69592833c51.jpg\"]','中国大陆','2026-09-15 00:00:00',0.00,'邱礼涛继《扫毒2》《拆弹专家2》后携《扫毒3：人在天涯》强势回归，古天乐郭富城刘青云三大影帝首次同台飙戏荡平金三角！毒枭康素差（刘青云 饰）和手下张建行（郭富城 饰）、欧志远（古天乐 饰）因一次意外有了过命交情，三人情同手足。康素差被香港警方通缉后带领团队逃到金三角发展，却意外发现身边藏有卧底。曾经的生死兄弟如今分崩离析，敌友难辨，何去何从……','[\"/images/movie/2023/07/08/5f4fe51072604f4f8462b4ec48099949.jpg\", \"/images/movie/2023/07/08/a1fd14630e0d448ba64fba9a9041fbba.jpg\", \"/images/movie/2023/07/08/6126fc55631047a3b07d27ad4e71372c.jpg\", \"/images/movie/2023/07/08/bbf4b074d6f649508d25f798bc2ff8bc.jpg\", \"/images/movie/2023/07/08/e79f8b5cc069451ca305ffc39597524c.jpg\"]',0),(5,'封神第一部',119,'[\"/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg\"]','中国大陆','2026-08-10 00:00:00',0.00,'中国国民神话史诗大片，震撼视效燃炸暑期！《封神第一部》讲述商王殷寿勾结狐妖妲己，暴虐无道，引发天谴。昆仑仙人姜子牙携“封神榜”下山，寻找天下共主，以救苍生。西伯侯之子姬发逐渐发现殷寿的本来面目，反出朝歌。各方势力暗流涌动，风云变幻端倪初显……三千年想象成真，恢弘史诗再创新，见证中国神话崛起！','[\"/images/movie/2023/07/08/57c6d183aa94440fb1ba794c6a38deae.jpg\",\"/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg\",\"/images/movie/2023/07/08/f1c5db2c9ed44e419736713ec46f741c.jpg\",\"/images/movie/2023/07/08/5c4f08c6670a4a0f95f34a8ba1b25c7c.jpg\",\"/images/movie/2023/07/08/7bffc009cb3c4ba2a93c37c7ad0de204.jpg\"]',0),(6,'我爱你！',120,'[\"/images/movie/2023/07/08/fe5caaf26e54486089581917d79fcbaf.jpg\"]','中国大陆','2026-08-15 00:00:00',0.00,'影帝影后绝赞演技，年度爱情片神作，带你领悟爱情真谛。你是否想过自己会如何老去？四个花甲老人，两段迟暮之恋，他们的爱善良而纯粹、浪漫又浓烈。在生命这段有限的旅程里，趁还来得及，我要对你说声“我爱你！”。','[\"/images/movie/2023/07/08/5e54da8a222a43b7a8ea6b440a693a42.jpg\", \"/images/movie/2023/07/08/b3bc5af799354b18b77d0a402a0a0332.jpg\", \"/images/movie/2023/07/08/87ba4f68fae34520a2b664038564ba28.jpg\", \"/images/movie/2023/07/08/c111499f7068491bb3bbf99714ab1c61.jpg\", \"/images/movie/2023/07/08/d5116527077e4f30939eb58703a51460.jpg\"]',0),(7,' 变形金刚：超能勇士崛起',130,'[\"/images/movie/2023/07/08/e04f06dc02b84d38bc4d1ba2b39add0d.jpg\"]','美国','2026-08-20 00:00:00',0.00,'2023年顶级大银幕视觉盛宴来袭！时隔5年，变形金刚震撼归来！故事重返上世纪90年代，终极反派宇宙大帝从天而降，驱使以天灾为首的恐惧兽掀起地球危机。绝境之中，蛰伏许久的巨无霸终觉醒，联合汽车人变形出发！一场前所未有的史诗决战即将上演！','[\"/images/movie/2023/07/08/abd8b63064cb41babbb8d9c1608daebb.jpg\", \"/images/movie/2023/07/08/67e51c6e84bd49efa0abbd6d7262a7cd.jpg\", \"/images/movie/2023/07/08/d6eb9956a31942bebac3ef8f3e65f1fe.jpg\", \"/images/movie/2023/07/08/f0ee1b5dc1a446cba6f90b577f3fa203.jpg\", \"/images/movie/2023/07/08/a9dc4522a74f4441b941b6c72442bcb5.jpg\"]',0),(8,'超级飞侠：乐迪加速',140,'[\"/images/movie/2023/07/08/c940dfecf0fc4ced810c8107f0182f02.png\"]','中国大陆','2026-09-01 00:00:00',0.00,'超级飞侠乐迪接到一项新任务！一个神秘的包裹，一次跨越大洲的派送，乐迪却因此偶然介入了一场将世界陷于危机的恶作剧中。面对危机，乐迪和其他超级飞侠将发挥各自的救援能力，争分夺秒合力拯救世界！','[\"/images/movie/2023/07/08/5bf5afbdf78e49058917e3e810e06f53.jpg\", \"/images/movie/2023/07/08/ba022fa6124b42d89869ca020473eaa9.jpg\", \"/images/movie/2023/07/08/6f176713bb784aa5a37940b9d76a3699.jpg\", \"/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg\", \"/images/movie/2023/07/08/b73b804fc0cd4c4fbe4e13eae13f5203.jpg\"]',0),(9,'荒野咖啡馆',140,'[\"/images/movie/2023/07/08/56439786da7548c188e785da3e9f636b.jpg\"]','中国大陆','2029-11-02 00:02:00',0.00,'在中国西部一座工业小城里，以寒远芳、大梨、小安为代表的年轻人，心中充满了对“远方”的幻想和执着，电影将以冷静沉着的笔调，勾勒寂寞小镇里平凡少年与少女的躁动与不安。有人在不甘中沉沦，也有人在冲动之下勇敢迈出了求变的步伐。青春的力量裹挟着人们，在时代的大背景下，奔赴梦想。据主创介绍，影片的整体风格将在真实性与形式感之间寻求一种完美的平衡，以映衬现实的残酷和青春的美好。','[\"/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg\", \"/images/movie/2023/07/08/78a24b55bdf047e2a3a9737a8650eec2.jpg\", \"/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg\", \"/images/movie/2023/07/08/62a548a7529a4231bcd97150e251868a.jpg\", \"/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg\"]',0),(10,'战狼',200,'[\"/images/movie/2023/07/08/690577aa9fdf4fde81bfbb61d487eb91.jpg\"]','中国大陆','2029-10-15 00:00:00',0.00,'痞性十足的冷锋 （ 吴京 饰）屡屡惹祸，有人说他是 流氓，是 痞子， 也有人说他是 英雄，是传奇，在一次行动中冷锋违抗军令打死了恐怖分子，要被开除出队，却意外得到了神秘部队战狼的接纳，但本想换个地方继续惹祸的他却跳进了另外一个深渊，冷傲的战狼副队长，擦出暧昧火花的性感女队长 （ 余男 饰），心计颇深腹黑的毒枭，枉死的队友， 雇佣兵跨过边境线入侵中国，一切都使他陷入了麻烦中。一切都在考验这个团队的毒瘤冷锋，他不知该何去何从。','[\"/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg\", \"/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg\", \"/images/movie/2023/07/08/f3fb556653f841d980c31057d0e2608b.jpg\", \"/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg\", \"/images/movie/2023/07/08/60c7d1baf2a74239bad393c39767adff.jpg\"]',0),(11,'舞者',100,'[\"/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg\"]','中国大陆','2029-05-21 00:00:00',0.00,'小学六年级的学生夏思梦自幼热爱舞蹈，心中一直藏着一个舞蹈家的梦想，她有着良好的舞蹈基础，却从来不在人前跳舞，只有当她在独处之时，她才会随着潺潺溪流，在风中翩翩起舞……','[\"/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg\", \"/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg\", \"/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg\", \"/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg\", \"/images/movie/2023/07/08/553600afb5114f358ab825c1fc4644aa.jpeg\"]',0),(12,'碟中谍7：致命清算（上）',140,'[\"/images/movie/2023/07/08/736dcfa997ed4712ac3ed94dfd49c234.jpg\"]','美国','2029-10-24 00:00:00',840.00,'刷新极限的传奇特工系列火线回归，感受今夏最真实震撼的银幕冒险！特工伊森·亨特（汤姆·克鲁斯饰）和他的IMF小组将开启迄今为止最危险的一次任务：追踪一种会危及全人类性命的新型武器，并阻止其落入坏人之手。与此同时，伊森曾对抗过的黑暗势力也正在卷土重来，整个世界的命运岌岌可危。面对神秘而强大的敌人，他不得不面对选择使命还是至爱的终极抉择。','[\"/images/movie/2023/07/08/99096ff662db40cf944399639dd5c431.jpg\", \"/images/movie/2023/07/08/e60f6a7a52f2466281fdf213687e0413.jpg\", \"/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg\", \"/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg\", \"/images/movie/2023/07/08/b9d414ccd4ee4078bd206f67a297efbd.jpg\"]',0),(31,'拯救嫌疑人',90,'[\"/images/movie/2023/12/25/c7b24b9c749d4b33af0b7f66c2db3fa1.jpg\"]','中国大陆','2026-10-01 00:00:00',290.00,'拯救嫌疑人','[\"/images/movie/2023/12/25/12171b8309784bca96830fe64bd67ec1.png\",\"/images/movie/2023/12/25/1828b4b2add3400da8f7549ecfa5272e.jpg\"]',0),(32,'长津湖',176,'[\"/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg\"]','中国大陆','2026-07-01 00:00:00',577535.00,'1950年，中国志愿军部队在极度严酷环境下坚守阵地奋勇杀敌，为长津湖战役胜利作出重要贡献的历史故事。','[\"/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg\", \"/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg\"]',0),(33,'红海行动',138,'[\"/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg\"]','中国大陆','2018-02-16 00:00:00',365250.00,'中国海军蛟龙突击队8人小组奉命执行撤侨任务，在异国他乡遭遇伏击，突击队成员浴血奋战解救人质的故事。','[\"/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg\", \"/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg\"]',0),(34,'八佰',147,'[\"/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg\"]','中国大陆','2026-06-01 00:00:00',311100.00,'1937年淞沪会战末期，国民革命军第88师524团留守上海四行仓库，与租界一河之隔，孤军奋战四昼夜的壮烈故事。','[\"/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg\", \"/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg\"]',0),(35,'敦刻尔克',107,'[\"/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg\"]','英国/美国','2017-07-21 00:00:00',34100.00,'二战期间，英法联军被敌军包围在敦刻尔克海滩，英国政府和海军发动大批船员和民众营救被困士兵的故事。','[\"/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg\", \"/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg\"]',0),(36,'拯救大兵瑞恩',169,'[\"/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg\"]','美国','1998-07-24 00:00:00',48000.00,'二战期间，一支美军小队深入敌后，冒着生命危险寻找并带回一名失去了三个兄长的伞兵瑞恩。','[\"/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg\", \"/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg\"]',0),(37,'满江红',159,'[\"/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg\"]','中国大陆','2026-06-10 00:00:00',454400.00,'南宋绍兴年间，岳飞死后四年，秦桧率兵与金国会谈。一个小兵与亲兵营副统领被迫卷入一场巨大的阴谋中。','[\"/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg\", \"/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg\"]',0),(38,'妖猫传',129,'[\"/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg\"]','中国大陆','2017-12-22 00:00:00',52900.00,'盛唐时期，一只口吐人言的妖猫在长安城掀起骚动，诗人白乐天与僧人空海联手调查妖猫背后的秘密。','[\"/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg\", \"/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg\"]',0),(39,'影',116,'[\"/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg\"]','中国大陆','2018-09-30 00:00:00',62900.00,'一个从小被秘密囚禁的替身「影子」，在主人遇刺后被迫扮演主人角色，周旋于朝堂与战场之间。',