--
-- Table structure for table `sys_session`
--

DROP TABLE IF EXISTS `sys_session`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_session` (
  `session_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '场次编号',
  `hall_id` bigint unsigned NOT NULL COMMENT '影厅编号',
  `language_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '语言版本',
  `movie_id` bigint unsigned NOT NULL COMMENT '电影编号',
  `play_time` time NOT NULL COMMENT '播放时间',
  `end_time` time NOT NULL COMMENT '散场时间',
  `deadline` datetime DEFAULT NULL COMMENT '截止时间，此时间之前不可删不可改',
  `session_date` date NOT NULL COMMENT '场次日期',
  `session_price` decimal(10,2) NOT NULL COMMENT '票价',
  `session_tips` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '影厅提示(如是否需要戴口罩，有什么福利，显示在选座购票位置的影厅后边，格式类似：6号Barco厅-（戴口罩勿饮食）凭票领券免费停车3小时)',
  `session_seats` varchar(1600) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '座位信息，采用{key: [], key: []}存储每一个座位的状态，其中key表示排，数组(下标+1)表示几号座，存储的值为0表示可选，1表示空(无座位)，值为2表示已选择，值为3表示已售出，',
  `seat_nums` smallint unsigned DEFAULT '0' COMMENT '总座位数',
  `sall_nums` smallint NOT NULL DEFAULT '0' COMMENT '售出座位数',
  `del_state` tinyint NOT NULL DEFAULT '0' COMMENT '删除标记，0未删除，1删除，默认0',
  PRIMARY KEY (`session_id`) USING BTREE,
  KEY `idx_session_hall_id` (`hall_id`),
  KEY `idx_session_movie_id` (`movie_id`),
  KEY `idx_session_date` (`session_date`),
  KEY `idx_session_del_state` (`del_state`),
  CONSTRAINT `fk_session_hall` FOREIGN KEY (`hall_id`) REFERENCES `sys_hall` (`hall_id`) ON DELETE RESTRICT ON UPDATE CASCADE,
  CONSTRAINT `fk_session_movie` FOREIGN KEY (`movie_id`) REFERENCES `sys_movie` (`movie_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=521 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC;
/*!40101 SET character_set_client = @saved_cs_client */;

